describe('_flush guard condition with waitForDrain', () => {
  it('should emit drain exactly once after all pending writes complete', (done) => {
    const tmpDir = os.tmpdir();
    const file = path.join(tmpDir, `dirty-mutant-${Date.now()}.dirty`);
    const db = new Dirty(file);
    let drainCount = 0;

    db.on('load', () => {
      // Write many large values to try to fill the write stream buffer
      // and trigger _waitForDrain = true
      const largeVal = 'x'.repeat(10000);
      for (let i = 0; i < 100; i++) {
        db.set(`key${i}`, largeVal);
      }

      db.on('drain', () => {
        drainCount++;
        // After drain, verify all 100 keys are present
        for (let i = 0; i < 100; i++) {
          expect(db.get(`key${i}`)).toBe(largeVal);
        }
        try { fs.unlinkSync(file); } catch (e) { /* ignore */ }
        expect(drainCount).toBe(1);
        done();
      });
